'use client';
import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { ArrowLeft, Sparkles, Send, Check } from 'lucide-react';
import Link from 'next/link';
import { supabase, isValidEmail } from '@/lib/supabase';

interface FormData {
    // Requester info
    name: string;
    email: string;

    // About the person
    person_full_name: string;
    person_birth_date: string;
    person_death_date: string;
    relationship: string;

    // Materials
    materials_photos: boolean;
    materials_photos_count: string;
    materials_documents: boolean;
    materials_videos: boolean;
    materials_audio: boolean;
    materials_letters: boolean;
    materials_digital: boolean;
    materials_other: string;

    // Intentions
    preservation_priorities: string;
    sensitive_aspects: string;

    // Preferences
    contact_preference: 'email' | 'call';
}

export default function ConciergeRequestPage() {
    const router = useRouter();
    const [formData, setFormData] = useState<FormData>({
        name: '',
        email: '',
        person_full_name: '',
        person_birth_date: '',
        person_death_date: '',
        relationship: '',
        materials_photos: false,
        materials_photos_count: '',
        materials_documents: false,
        materials_videos: false,
        materials_audio: false,
        materials_letters: false,
        materials_digital: false,
        materials_other: '',
        preservation_priorities: '',
        sensitive_aspects: '',
        contact_preference: 'email'
    });

    const [isSubmitting, setIsSubmitting] = useState(false);
    const [error, setError] = useState<string | null>(null);

    const handleChange = (field: keyof FormData, value: any) => {
        setFormData(prev => ({ ...prev, [field]: value }));
        setError(null);
    };

    const validateForm = (): boolean => {
        if (!formData.name.trim()) {
            setError('Please enter your name');
            return false;
        }
        if (!formData.email.trim()) {
            setError('Please enter your email');
            return false;
        }
        if (!isValidEmail(formData.email)) {
            setError('Please enter a valid email address');
            return false;
        }
        if (!formData.person_full_name.trim()) {
            setError('Please enter the name of the person to honor');
            return false;
        }
        if (!formData.relationship.trim()) {
            setError('Please specify your relationship');
            return false;
        }
        if (!formData.preservation_priorities.trim()) {
            setError('Please share what must be preserved');
            return false;
        }
        return true;
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();

        if (!validateForm()) return;

        setIsSubmitting(true);
        setError(null);

        try {
            // Prepare materials inventory
            const materials_inventory = {
                photos: formData.materials_photos,
                photos_count: formData.materials_photos_count,
                documents: formData.materials_documents,
                videos: formData.materials_videos,
                audio: formData.materials_audio,
                letters: formData.materials_letters,
                digital: formData.materials_digital,
                other: formData.materials_other
            };

            // Create concierge project
            const { data, error: insertError } = await supabase
                .from('concierge_projects')
                .insert([{
                    name: formData.name.trim(),
                    email: formData.email.trim(),
                    person_full_name: formData.person_full_name.trim(),
                    person_birth_date: formData.person_birth_date || null,
                    person_death_date: formData.person_death_date || null,
                    relationship: formData.relationship.trim(),
                    materials_inventory: materials_inventory,
                    preservation_priorities: formData.preservation_priorities.trim(),
                    sensitive_aspects: formData.sensitive_aspects.trim() || null,
                    contact_preference: formData.contact_preference,
                    status: 'requested',
                    paid: false
                }])
                .select()
                .single();

            if (insertError) throw insertError;

            if (data) {
                router.push(`/concierge/requested?id=${data.id}`);
            }
        } catch (err: any) {
            console.error('Error submitting request:', err);
            setError('Something went wrong. Please try again or contact us directly.');
        } finally {
            setIsSubmitting(false);
        }
    };

    return (
        <div className="min-h-screen bg-gradient-to-br from-sage/5 via-ivory to-terracotta/5">
            {/* Header */}
            <div className="border-b border-sand/30 bg-white/80 backdrop-blur-sm">
                <div className="max-w-4xl mx-auto px-6 py-6">
                    <Link
                        href="/choice"
                        className="inline-flex items-center gap-2 text-charcoal/60 hover:text-charcoal transition-colors"
                    >
                        <ArrowLeft size={20} />
                        <span>Back to options</span>
                    </Link>
                </div>
            </div>

            {/* Main Content */}
            <div className="max-w-3xl mx-auto px-6 py-16">
                {/* Icon */}
                <div className="flex justify-center mb-8">
                    <div className="w-20 h-20 bg-gradient-to-br from-sage via-terracotta to-sage/80 rounded-2xl flex items-center justify-center shadow-lg">
                        <Sparkles size={40} className="text-ivory" />
                    </div>
                </div>

                {/* Heading */}
                <div className="text-center mb-12">
                    <h1 className="font-serif text-5xl text-charcoal mb-4">
                        Concierge Service
                    </h1>
                    <p className="text-xl text-charcoal/70 leading-relaxed max-w-xl mx-auto">
                        We handle everything. You simply share what you have, and we create a lasting archive.
                    </p>
                </div>

                {/* Form */}
                <form onSubmit={handleSubmit} className="space-y-12">
                    {error && (
                        <div className="p-4 bg-red-50 border border-red-200 rounded-xl text-sm text-red-800">
                            {error}
                        </div>
                    )}

                    {/* Section 1: Your Information */}
                    <div className="bg-white rounded-2xl border border-sand/30 shadow-sm p-8">
                        <h2 className="font-serif text-2xl text-charcoal mb-6">Your Information</h2>

                        <div className="space-y-6">
                            <div>
                                <label htmlFor="name" className="block text-sm font-medium text-charcoal mb-2">
                                    Your name <span className="text-terracotta">*</span>
                                </label>
                                <input
                                    id="name"
                                    type="text"
                                    value={formData.name}
                                    onChange={(e) => handleChange('name', e.target.value)}
                                    placeholder="e.g., Marie Dubois"
                                    className="w-full px-4 py-3 border border-sand/40 rounded-xl focus:outline-none focus:ring-2 focus:ring-sage/30 focus:border-sage transition-all"
                                    disabled={isSubmitting}
                                />
                            </div>

                            <div>
                                <label htmlFor="email" className="block text-sm font-medium text-charcoal mb-2">
                                    Your email <span className="text-terracotta">*</span>
                                </label>
                                <input
                                    id="email"
                                    type="email"
                                    value={formData.email}
                                    onChange={(e) => handleChange('email', e.target.value)}
                                    placeholder="marie@example.com"
                                    className="w-full px-4 py-3 border border-sand/40 rounded-xl focus:outline-none focus:ring-2 focus:ring-sage/30 focus:border-sage transition-all"
                                    disabled={isSubmitting}
                                />
                            </div>
                        </div>
                    </div>

                    {/* Section 2: About the Person */}
                    <div className="bg-white rounded-2xl border border-sand/30 shadow-sm p-8">
                        <h2 className="font-serif text-2xl text-charcoal mb-2">Who are we honoring?</h2>
                        <p className="text-sm text-charcoal/60 mb-6">Tell us about the person whose memory you wish to preserve</p>

                        <div className="space-y-6">
                            <div>
                                <label htmlFor="person_name" className="block text-sm font-medium text-charcoal mb-2">
                                    Full name <span className="text-terracotta">*</span>
                                </label>
                                <input
                                    id="person_name"
                                    type="text"
                                    value={formData.person_full_name}
                                    onChange={(e) => handleChange('person_full_name', e.target.value)}
                                    placeholder="e.g., Eleanor Marie Thompson"
                                    className="w-full px-4 py-3 border border-sand/40 rounded-xl focus:outline-none focus:ring-2 focus:ring-sage/30 focus:border-sage transition-all"
                                    disabled={isSubmitting}
                                />
                            </div>

                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                <div>
                                    <label htmlFor="birth_date" className="block text-sm font-medium text-charcoal mb-2">
                                        Birth date <span className="text-charcoal/40">(optional)</span>
                                    </label>
                                    <input
                                        id="birth_date"
                                        type="date"
                                        value={formData.person_birth_date}
                                        onChange={(e) => handleChange('person_birth_date', e.target.value)}
                                        className="w-full px-4 py-3 border border-sand/40 rounded-xl focus:outline-none focus:ring-2 focus:ring-sage/30 focus:border-sage transition-all"
                                        disabled={isSubmitting}
                                    />
                                </div>

                                <div>
                                    <label htmlFor="death_date" className="block text-sm font-medium text-charcoal mb-2">
                                        Death date <span className="text-charcoal/40">(if applicable)</span>
                                    </label>
                                    <input
                                        id="death_date"
                                        type="date"
                                        value={formData.person_death_date}
                                        onChange={(e) => handleChange('person_death_date', e.target.value)}
                                        className="w-full px-4 py-3 border border-sand/40 rounded-xl focus:outline-none focus:ring-2 focus:ring-sage/30 focus:border-sage transition-all"
                                        disabled={isSubmitting}
                                    />
                                </div>
                            </div>

                            <div>
                                <label htmlFor="relationship" className="block text-sm font-medium text-charcoal mb-2">
                                    Your relationship to this person <span className="text-terracotta">*</span>
                                </label>
                                <input
                                    id="relationship"
                                    type="text"
                                    value={formData.relationship}
                                    onChange={(e) => handleChange('relationship', e.target.value)}
                                    placeholder="e.g., Granddaughter, Son, Niece..."
                                    className="w-full px-4 py-3 border border-sand/40 rounded-xl focus:outline-none focus:ring-2 focus:ring-sage/30 focus:border-sage transition-all"
                                    disabled={isSubmitting}
                                />
                            </div>
                        </div>
                    </div>

                    {/* Section 3: Materials Inventory */}
                    <div className="bg-white rounded-2xl border border-sand/30 shadow-sm p-8">
                        <h2 className="font-serif text-2xl text-charcoal mb-2">What do you already have?</h2>
                        <p className="text-sm text-charcoal/60 mb-6">Check all that apply — no need to be precise, we just want to understand</p>

                        <div className="space-y-4">
                            {/* Photos */}
                            <div className="flex items-start gap-3 p-4 bg-sand/5 rounded-xl">
                                <input
                                    type="checkbox"
                                    id="materials_photos"
                                    checked={formData.materials_photos}
                                    onChange={(e) => handleChange('materials_photos', e.target.checked)}
                                    className="mt-1 w-5 h-5 text-sage border-sand/40 rounded focus:ring-sage/30"
                                    disabled={isSubmitting}
                                />
                                <div className="flex-1">
                                    <label htmlFor="materials_photos" className="font-medium text-charcoal cursor-pointer">
                                        Photographs
                                    </label>
                                    {formData.materials_photos && (
                                        <input
                                            type="text"
                                            value={formData.materials_photos_count}
                                            onChange={(e) => handleChange('materials_photos_count', e.target.value)}
                                            placeholder="Approximately how many? (e.g., 50-100, several boxes, etc.)"
                                            className="mt-2 w-full px-3 py-2 text-sm border border-sand/40 rounded-lg focus:outline-none focus:ring-2 focus:ring-sage/30"
                                            disabled={isSubmitting}
                                        />
                                    )}
                                </div>
                            </div>

                            {/* Documents */}
                            <div className="flex items-start gap-3 p-4 bg-sand/5 rounded-xl">
                                <input
                                    type="checkbox"
                                    id="materials_documents"
                                    checked={formData.materials_documents}
                                    onChange={(e) => handleChange('materials_documents', e.target.checked)}
                                    className="mt-1 w-5 h-5 text-sage border-sand/40 rounded focus:ring-sage/30"
                                    disabled={isSubmitting}
                                />
                                <label htmlFor="materials_documents" className="font-medium text-charcoal cursor-pointer">
                                    Official documents (birth certificates, passports, diplomas, etc.)
                                </label>
                            </div>

                            {/* Videos */}
                            <div className="flex items-start gap-3 p-4 bg-sand/5 rounded-xl">
                                <input
                                    type="checkbox"
                                    id="materials_videos"
                                    checked={formData.materials_videos}
                                    onChange={(e) => handleChange('materials_videos', e.target.checked)}
                                    className="mt-1 w-5 h-5 text-sage border-sand/40 rounded focus:ring-sage/30"
                                    disabled={isSubmitting}
                                />
                                <label htmlFor="materials_videos" className="font-medium text-charcoal cursor-pointer">
                                    Videos or film recordings
                                </label>
                            </div>

                            {/* Audio */}
                            <div className="flex items-start gap-3 p-4 bg-sand/5 rounded-xl">
                                <input
                                    type="checkbox"
                                    id="materials_audio"
                                    checked={formData.materials_audio}
                                    onChange={(e) => handleChange('materials_audio', e.target.checked)}
                                    className="mt-1 w-5 h-5 text-sage border-sand/40 rounded focus:ring-sage/30"
                                    disabled={isSubmitting}
                                />
                                <label htmlFor="materials_audio" className="font-medium text-charcoal cursor-pointer">
                                    Audio recordings (voice messages, interviews, etc.)
                                </label>
                            </div>

                            {/* Letters */}
                            <div className="flex items-start gap-3 p-4 bg-sand/5 rounded-xl">
                                <input
                                    type="checkbox"
                                    id="materials_letters"
                                    checked={formData.materials_letters}
                                    onChange={(e) => handleChange('materials_letters', e.target.checked)}
                                    className="mt-1 w-5 h-5 text-sage border-sand/40 rounded focus:ring-sage/30"
                                    disabled={isSubmitting}
                                />
                                <label htmlFor="materials_letters" className="font-medium text-charcoal cursor-pointer">
                                    Letters or written correspondence
                                </label>
                            </div>

                            {/* Digital */}
                            <div className="flex items-start gap-3 p-4 bg-sand/5 rounded-xl">
                                <input
                                    type="checkbox"
                                    id="materials_digital"
                                    checked={formData.materials_digital}
                                    onChange={(e) => handleChange('materials_digital', e.target.checked)}
                                    className="mt-1 w-5 h-5 text-sage border-sand/40 rounded focus:ring-sage/30"
                                    disabled={isSubmitting}
                                />
                                <label htmlFor="materials_digital" className="font-medium text-charcoal cursor-pointer">
                                    Digital content (emails, messages, social media, etc.)
                                </label>
                            </div>

                            {/* Other */}
                            <div className="p-4 bg-sand/5 rounded-xl">
                                <label htmlFor="materials_other" className="block text-sm font-medium text-charcoal mb-2">
                                    Other materials
                                </label>
                                <input
                                    id="materials_other"
                                    type="text"
                                    value={formData.materials_other}
                                    onChange={(e) => handleChange('materials_other', e.target.value)}
                                    placeholder="Anything else we should know about?"
                                    className="w-full px-3 py-2 text-sm border border-sand/40 rounded-lg focus:outline-none focus:ring-2 focus:ring-sage/30"
                                    disabled={isSubmitting}
                                />
                            </div>
                        </div>
                    </div>

                    {/* Section 4: Intentions */}
                    <div className="bg-white rounded-2xl border border-sand/30 shadow-sm p-8">
                        <h2 className="font-serif text-2xl text-charcoal mb-2">Your intentions</h2>
                        <p className="text-sm text-charcoal/60 mb-6">Help us understand what matters most</p>

                        <div className="space-y-6">
                            <div>
                                <label htmlFor="preservation_priorities" className="block text-sm font-medium text-charcoal mb-2">
                                    What must absolutely be preserved? <span className="text-terracotta">*</span>
                                </label>
                                <textarea
                                    id="preservation_priorities"
                                    value={formData.preservation_priorities}
                                    onChange={(e) => handleChange('preservation_priorities', e.target.value)}
                                    placeholder="Share what's most important to preserve about this person's story. There's no rush — take your time to express what matters."
                                    rows={6}
                                    className="w-full px-4 py-3 border border-sand/40 rounded-xl focus:outline-none focus:ring-2 focus:ring-sage/30 focus:border-sage transition-all resize-none"
                                    disabled={isSubmitting}
                                />
                                <p className="text-xs text-charcoal/40 mt-2">
                                    Examples: values they embodied, lessons they taught, moments that defined them, impact they had on others
                                </p>
                            </div>

                            <div>
                                <label htmlFor="sensitive_aspects" className="block text-sm font-medium text-charcoal mb-2">
                                    Are there delicate or sensitive aspects to consider? <span className="text-charcoal/40">(optional)</span>
                                </label>
                                <textarea
                                    id="sensitive_aspects"
                                    value={formData.sensitive_aspects}
                                    onChange={(e) => handleChange('sensitive_aspects', e.target.value)}
                                    placeholder="Family tensions, private matters, subjects to handle with care... We treat everything with discretion."
                                    rows={4}
                                    className="w-full px-4 py-3 border border-sand/40 rounded-xl focus:outline-none focus:ring-2 focus:ring-sage/30 focus:border-sage transition-all resize-none"
                                    disabled={isSubmitting}
                                />
                            </div>
                        </div>
                    </div>

                    {/* Section 5: Contact Preference */}
                    <div className="bg-white rounded-2xl border border-sand/30 shadow-sm p-8">
                        <h2 className="font-serif text-2xl text-charcoal mb-2">How should we reach you?</h2>
                        <p className="text-sm text-charcoal/60 mb-6">Choose how you'd prefer to continue this conversation</p>

                        <div className="space-y-3">
                            <label className="flex items-start gap-4 p-4 border-2 border-sand/40 rounded-xl cursor-pointer hover:border-sage/40 hover:bg-sage/5 transition-all">
                                <input
                                    type="radio"
                                    name="contact_preference"
                                    value="email"
                                    checked={formData.contact_preference === 'email'}
                                    onChange={(e) => handleChange('contact_preference', 'email')}
                                    className="mt-1 w-5 h-5 text-sage border-sand/40 focus:ring-sage/30"
                                    disabled={isSubmitting}
                                />
                                <div className="flex-1">
                                    <p className="font-medium text-charcoal">Email correspondence</p>
                                    <p className="text-sm text-charcoal/60 mt-1">We'll guide you step by step via email. You can respond at your own pace.</p>
                                </div>
                            </label>

                            <label className="flex items-start gap-4 p-4 border-2 border-sand/40 rounded-xl cursor-pointer hover:border-sage/40 hover:bg-sage/5 transition-all">
                                <input
                                    type="radio"
                                    name="contact_preference"
                                    value="call"
                                    checked={formData.contact_preference === 'call'}
                                    onChange={(e) => handleChange('contact_preference', 'call')}
                                    className="mt-1 w-5 h-5 text-sage border-sand/40 focus:ring-sage/30"
                                    disabled={isSubmitting}
                                />
                                <div className="flex-1">
                                    <p className="font-medium text-charcoal">Schedule a call</p>
                                    <p className="text-sm text-charcoal/60 mt-1">We'll plan a conversation to discuss everything in detail.</p>
                                </div>
                            </label>
                        </div>
                    </div>

                    {/* Submit */}
                    <div className="pt-4">
                        <button
                            type="submit"
                            disabled={isSubmitting}
                            className="w-full py-5 bg-gradient-to-r from-sage to-terracotta hover:shadow-lg text-ivory rounded-xl font-semibold text-lg transition-all flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
                        >
                            {isSubmitting ? (
                                <>
                                    <div className="w-5 h-5 border-2 border-ivory/30 border-t-ivory rounded-full animate-spin" />
                                    Sending...
                                </>
                            ) : (
                                <>
                                    <Send size={20} />
                                    Submit Request
                                </>
                            )}
                        </button>

                        <p className="text-xs text-center text-charcoal/50 mt-4">
                            No payment required now. We'll discuss everything before proceeding.
                        </p>
                    </div>
                </form>

                {/* Reassurance */}
                <div className="mt-12 text-center">
                    <p className="text-sm text-charcoal/60 leading-relaxed max-w-2xl mx-auto">
                        We'll respond within 24 hours. Everything you share is treated with complete discretion.
                    </p>
                </div>
            </div>
        </div>
    );
}